// ─── 헬퍼 ─────────────────────────────────────────────
function getPayChecks(method) {
  const m = (method || '').replace(/\s/g, '');
  const has = (...kw) => kw.some(k => m.includes(k));
  return {
    dw:   has('직수금', '송금') && !has('자동') ? '○' : '',
    auto: has('자동이체') ? '○' : '',
    card: has('카드')     ? '○' : '',
    cash: has('현금')     ? '○' : '',
    wire: has('송금') && !has('자동') ? '○' : '',
  };
}

function getLandline(phone) {
  if (!phone) return '';
  return phone.split(/[\/,]/).map(p => p.trim())
    .filter(p => p && !p.toUpperCase().includes('F)') && !p.startsWith('010'))
    .join(', ') || (phone.split(/[\/,]/)[0]?.trim() || '');
}

function getStaffMobile(staffName, staffList) {
  if (!staffName || !staffList?.length) return '';
  const staff = staffList.find(s => s.name === staffName);
  if (!staff) return '';
  return (staff.phone || staff.mobile || '').split(/[\/,]/)
    .map(p => p.trim()).find(p => p.startsWith('010')) || '';
}

function calcTotal(c) {
  const svc = c.services?.length
    ? c.services.reduce((s, sv) => s + N(sv.price), 0)
    : N(c.price);
  const eq = c.equipment;
  return svc + (eq?.enabled && eq?.count && eq?.pricePerUnit ? eq.count * eq.pricePerUnit : 0);
}

// ─── 패널 컨트롤 HTML ─────────────────────────────────
function buildPanel(controls) {
  // onclick에 따옴표 충돌 방지: data-key + data-dir 방식
  const B = 'padding:2px 6px;background:rgba(255,255,255,0.15);color:white;border:none;border-radius:4px;cursor:pointer;font-size:14px;font-weight:bold;';
  const VS = 'font-size:11px;font-weight:bold;min-width:42px;text-align:center;color:#fde68a;cursor:pointer;border-bottom:1px dotted #fde68a;';
  const VN = 'font-size:11px;font-weight:bold;min-width:28px;text-align:center;color:#fde68a;cursor:pointer;border-bottom:1px dotted #fde68a;';

  var stepBar = '<div style="display:flex;align-items:center;gap:3px;padding:6px 0;margin-bottom:4px;border-bottom:2px solid rgba(255,255,255,0.2);">'
    + '<span style="font-size:10px;color:#fde68a;margin-right:2px;">이동:</span>';
  [0.5,1,2,5,10].forEach(function(s) {
    stepBar += '<button id="step-' + String(s).replace('.','_') + '" data-step="' + s + '" onclick="setStep(' + s + ')"'
      + ' style="' + B + '">' + s + '</button>';
  });
  stepBar += '<span style="font-size:9px;color:#93c5fd;margin-left:2px;">mm</span></div>';

  var items = controls.map(function(r) {
    if (r.sep) return '<div style="color:#93c5fd;font-size:10px;padding:5px 0 2px;font-weight:bold;">' + r.sep + '</div>';
    var vStyle = r.type === 'number' ? VN : VS;
    return '<div style="display:flex;align-items:center;gap:4px;padding:2px 0;border-bottom:1px solid rgba(255,255,255,0.06);">'
      + '<span style="flex:1;font-size:10px;color:#e0e7ff;">' + r.label + '</span>'
      + '<button data-key="' + r.key + '" data-dir="-1" onclick="adjBtn(this)" style="' + B + '">−</button>'
      + '<span id="v-' + r.key + '" data-key="' + r.key + '" onclick="directInput(this)" style="' + vStyle + '" title="클릭=직접입력"></span>'
      + '<button data-key="' + r.key + '" data-dir="1" onclick="adjBtn(this)" style="' + B + '">+</button>'
      + '</div>';
  }).join('');

  return stepBar + items;
}

// ─── 공통 팝업 JS ────────────────────────────────────
const POPUP_COMMON_JS = `
  function N(v){return Number(v)||0;}
  function F(v){return N(v).toLocaleString('ko-KR');}

  function applyWm(wmCfg, WM_KEY) {
    document.querySelectorAll('.wm').forEach(function(img) {
      img.style.top = wmCfg.offsetY + 'px';
      img.style.opacity = wmCfg.opacity / 100;
      img.style.display = wmCfg.visible ? 'block' : 'none';
    });
    var v=document.getElementById('wm-val');
    var o=document.getElementById('wm-opacity');
    var ov=document.getElementById('wm-op-val');
    var wb=document.getElementById('wm-btn');
    if(v) v.textContent = wmCfg.offsetY + 'px';
    if(o) o.value = wmCfg.opacity;
    if(ov) ov.textContent = wmCfg.opacity + '%';
    if(wb) wb.textContent = wmCfg.visible ? '👁️ 숨기기' : '👁️ 보이기';
    localStorage.setItem(WM_KEY, JSON.stringify(wmCfg));
  }

  function getChk(method) {
    var m=(method||'').replace(/\\s/g,'');
    var has=function(){for(var i=0;i<arguments.length;i++) if(m.includes(arguments[i])) return true; return false;};
    return {
      dw:   has('직수금','송금')&&!has('자동')?'○':'',
      auto: has('자동이체')?'○':'',
      card: has('카드')?'○':'',
      cash: has('현금')?'○':'',
      wire: has('송금')&&!has('자동')?'○':'',
    };
  }

  function calcTotal(c) {
    var svc=c.services&&c.services.length?c.services.reduce(function(s,sv){return s+N(sv.price);},0):N(c.price);
    var eq=c.equipment;
    return svc+(eq&&eq.enabled&&eq.count&&eq.pricePerUnit?eq.count*eq.pricePerUnit:0);
  }

  function shrink(text, maxLen, fs) {
    if (!text) return '';
    if (text.length <= maxLen) return text;
    var s=Math.max(5, fs*(maxLen/text.length)).toFixed(1);
    return '<span style="font-size:'+s+'pt">'+text+'</span>';
  }

  // 절대좌표 필드 생성 — container 기준
  function fld(text, xKey, yKey, cfg, FONT, extra) {
    if (text===null||text===undefined||text==='') return '';
    return '<span class="f" data-x="'+xKey+'" data-y="'+yKey+'"'
      +' style="position:absolute;left:'+cfg[xKey]+'mm;top:'+cfg[yKey]+'mm;'
      +'font-family:'+FONT+';'
      +'white-space:nowrap;overflow:hidden;line-height:1.2;z-index:2;'+(extra||'')+'">'
      +text+'</span>';
  }

  function fldAddr(text, xKey, yKey, cfg, FONT) {
    if (!text) return '';
    return '<span class="f" data-x="'+xKey+'" data-y="'+yKey+'"'
      +' style="position:absolute;left:'+cfg[xKey]+'mm;top:'+cfg[yKey]+'mm;'
      +'font-family:'+FONT+';'
      +'white-space:normal;word-break:keep-all;line-height:1.2;z-index:2;max-width:180mm;">'
      +text+'</span>';
  }

  function fldAmt(amt, xKey, yKey, cfg, FONT) {
    var val=N(amt);
    return '<span class="f" data-x="'+xKey+'" data-y="'+yKey+'"'
      +' style="position:absolute;left:'+cfg[xKey]+'mm;top:'+cfg[yKey]+'mm;'
      +'width:28mm;text-align:right;'
      +'font-family:'+FONT+';'
      +'white-space:nowrap;z-index:2;">'
      +(val?F(val):'')+'</span>';
  }

  // ── 스텝 관리 ──
  var curStep = 0.5;

  function setStep(s) {
    curStep = s;
    [0.5,1,2,5,10].forEach(function(v) {
      var el = document.getElementById('step-' + String(v).replace('.','_'));
      if (!el) return;
      el.style.background = (v === s) ? '#fde68a' : 'rgba(255,255,255,0.15)';
      el.style.color       = (v === s) ? '#1e3a8a' : 'white';
    });
  }

  // ── data-key/data-dir 방식 버튼 핸들러 ──
  function adjBtn(btn) {
    var k   = btn.dataset.key;
    var dir = Number(btn.dataset.dir);
    if (!k) return;
    if (k === 'copies') cfg[k] = Math.max(1, Math.round(cfg[k] + dir));
    else cfg[k] = Math.round((Number(cfg[k]) + dir * curStep) * 10) / 10;
    updateDisplay(cfg, DEFAULTS);
    applyToDOM(cfg);
    // 산업체 인쇄 버튼 갱신
    var pb = document.getElementById('print-btn');
    if (pb && cfg.copies !== undefined)
      pb.textContent = '\uD83D\uDDA8\uFE0F 인쇄 (' + (typeof customers !== 'undefined' ? customers.length : '') + '명 × ' + cfg.copies + '장)';
  }

  // ── 직접 입력 ──
  function directInput(spanEl) {
    var k = spanEl.dataset.key;
    if (!k) return;
    var cur = cfg[k];
    var inp = document.createElement('input');
    inp.type = 'number';
    inp.step = '0.5';
    inp.value = cur;
    inp.style.cssText = 'width:46px;font-size:11px;font-weight:bold;color:#1e3a8a;background:#fde68a;border:none;border-radius:3px;text-align:center;padding:1px 2px;';
    spanEl.parentNode.replaceChild(inp, spanEl);
    inp.focus(); inp.select();
    function commit() {
      var v = parseFloat(inp.value);
      if (!isNaN(v)) {
        if (k === 'copies') cfg[k] = Math.max(1, Math.round(v));
        else cfg[k] = Math.round(v * 10) / 10;
      }
      updateDisplay(cfg, DEFAULTS);
      applyToDOM(cfg);
      var pb = document.getElementById('print-btn');
      if (pb && cfg.copies !== undefined)
        pb.textContent = '\uD83D\uDDA8\uFE0F 인쇄 (' + (typeof customers !== 'undefined' ? customers.length : '') + '명 × ' + cfg.copies + '장)';
    }
    inp.addEventListener('keydown', function(e) {
      if (e.key === 'Enter')  { commit(); }
      if (e.key === 'Escape') { updateDisplay(cfg, DEFAULTS); }
    });
    inp.addEventListener('blur', commit);
  }

  function updateDisplay(cfg, DEFAULTS) {
    Object.keys(DEFAULTS).forEach(function(k) {
      var el=document.getElementById('v-'+k);
      if (!el || el.tagName==='INPUT') return;
      if (k==='fontSize') el.textContent=Number(cfg[k]).toFixed(1)+'pt';
      else if (k==='copies') el.textContent=cfg[k]+'장';
      else el.textContent=Number(cfg[k]).toFixed(1)+'mm';
    });
  }

  function applyToDOM(cfg) {
    // font-size는 <style id=font-style> 로 통합 적용
    var fs = document.getElementById('font-style');
    if(fs) fs.textContent = '.f{font-size:'+cfg.fontSize+'pt!important;}';
    document.querySelectorAll('[data-x]').forEach(function(el) {
      var k=el.dataset.x; if(cfg[k]!==undefined) el.style.left=cfg[k]+'mm';
    });
    document.querySelectorAll('[data-y]').forEach(function(el) {
      var k=el.dataset.y; if(cfg[k]!==undefined) el.style.top=cfg[k]+'mm';
    });
    // 커트라인 위치 업데이트 (소규모)
    document.querySelectorAll('.cutline-wrap').forEach(function(el) {
      if(cfg.cutline_y!==undefined) el.style.top=cfg.cutline_y+'mm';
    });
    var clLbl=document.querySelector('.cl-label');
    if(clLbl) clLbl.textContent='✂ '+cfg.cutline_y+'mm';
    var clLbl=document.querySelector('.cl-label');
    if(clLbl) clLbl.textContent='✂ '+cfg.cutline_y+'mm';
  }
`;

