// ─── 소규모 팝업 ─────────────────────────────────────
function openSmallPopup(customers, yearMonth) {
  const win = window.open('', '_blank', 'width=1100,height=900');
  if (!win) { alert('팝업이 차단되어 있습니다.'); return; }

  const BTN = `padding:2px 8px;background:rgba(255,255,255,0.15);color:white;border:none;border-radius:4px;cursor:pointer;font-size:14px;`;

  win.document.write(`<!DOCTYPE html>
<html lang="ko"><head><meta charset="UTF-8">
<title>소규모 서비스확인서 ${yearMonth}</title>
<style id="font-style"></style>
<style>
  @page { size:A4 portrait; margin:4.83mm 7.37mm 5.33mm 7.87mm; }
  *{box-sizing:border-box;margin:0;padding:0;}
  html,body{background:transparent;}
  /* page: A4 인쇄 영역 크기, relative 기준 */
  .page{width:194.76mm;height:286.84mm;position:relative;overflow:hidden;}
  .page+.page{page-break-before:always;}
  /* 상단 영역: page 기준 절대좌표 */
  .top-wrap{position:absolute;top:0;left:0;width:100%;height:100%;pointer-events:none;}
  /* 커트라인 wrapper: cutline_y mm 위치에서 시작, 하단은 여기서 0mm */
  .cutline-wrap{position:absolute;left:0;width:100%;pointer-events:none;}
  @media print{
    #panel,.no-print{display:none!important;}
    #preview,body{margin:0!important;padding:0!important;}
    .wm,.cl-line{display:none!important;}
  }
  @media screen{
    #panel{position:fixed;left:0;top:0;width:255px;height:100vh;background:#1e3a8a;overflow-y:auto;z-index:99;}
    #preview{margin-left:265px;padding:10px;}
    .wm{position:absolute;top:0;left:0;width:100%;height:100%;object-fit:fill;pointer-events:none;z-index:0;}
    .cl-line{position:absolute;left:0;right:0;top:0;height:0;border-top:2px dashed #ef4444;pointer-events:none;z-index:10;}
    .cl-label{position:absolute;left:6px;top:-20px;font-size:10px;color:#ef4444;font-weight:bold;background:rgba(255,255,255,0.9);padding:1px 5px;border-radius:3px;white-space:nowrap;}
  }
</style></head><body>

<div id="panel">
  <div style="padding:10px;">
    <div style="font-weight:bold;font-size:12px;color:white;margin-bottom:6px;">📐 소규모 좌표 조정</div>
    ${buildPanel(SMALL_CONTROLS)}
    <div style="display:flex;gap:6px;margin-top:10px;">
      <button onclick="saveCfg()" style="flex:1;padding:7px;background:#22c55e;color:white;border:none;border-radius:5px;cursor:pointer;font-size:12px;font-weight:bold;">💾 저장</button>
      <button onclick="resetCfg()" style="padding:7px 10px;background:rgba(255,255,255,0.15);color:white;border:none;border-radius:5px;cursor:pointer;font-size:11px;">↺ 초기화</button>
    </div>
    <button onclick="doPrint()" style="width:100%;margin-top:6px;padding:8px;background:#1d4ed8;color:white;border:none;border-radius:5px;cursor:pointer;font-size:12px;font-weight:bold;">🖨️ 인쇄 (${customers.length}명 × 1장)</button>
    <div style="font-size:9px;color:#fde68a;margin-top:4px;line-height:1.5;padding:4px 6px;background:rgba(0,0,0,0.2);border-radius:4px;">
      ⚠ 날짜/시간 머리글 제거:<br>
      인쇄창 → 설정 더보기<br>
      → <b>머리글 및 바닥글</b> 체크 해제
    </div>
    ${wmPanelHTML(BTN)}
    <button id="cl-btn" onclick="toggleCutline()"
      style="width:100%;margin-top:8px;padding:6px;background:rgba(239,68,68,0.2);color:#fca5a5;border:1px solid rgba(239,68,68,0.4);border-radius:5px;cursor:pointer;font-size:11px;font-weight:bold;">
      ✂ 커트라인 선 보기
    </button>
    <div style="font-size:9px;color:#93c5fd;margin-top:8px;line-height:1.4;">
      💡 ± 버튼은 이동단위 선택<br>
      ✂ 커트라인 Y = 절취선 위치<br>
      하단 Y = 커트라인 기준 독립 좌표<br>
      저장하면 다음에도 유지
    </div>
  </div>
</div>

<div id="preview">
  <div class="no-print" style="font-size:11px;color:#666;padding:0 0 8px;">
    ⬅ 패널에서 좌표 조정 후 💾 저장 → 🖨️ 인쇄 &nbsp;|&nbsp; 미리보기: ${customers[0]?.name || ''}
  </div>
  <div id="form-preview"></div>
</div>

<script>
  const SAVE_KEY = '${SAVE_KEY_SMALL}';
  const WM_KEY   = '${WM_SMALL_KEY}';
  const WM_IMG   = '${WM_SMALL}';
  const FONT     = '${FONT}';
  const DEFAULTS = ${JSON.stringify(SMALL_DEFAULTS)};
  const customers = ${JSON.stringify(customers)};

  ${POPUP_COMMON_JS}

  let cfg   = Object.assign({}, DEFAULTS);
  let wmCfg = {offsetY:0, opacity:25, visible:true};
  try { cfg   = Object.assign({}, DEFAULTS, JSON.parse(localStorage.getItem(SAVE_KEY)||'{}')); } catch(e){}
  try { wmCfg = Object.assign({}, wmCfg,   JSON.parse(localStorage.getItem(WM_KEY)||'{}')); } catch(e){}

  function adj(k, d) {
    if (k === 'copies') cfg[k] = Math.max(1, Math.round(cfg[k] + d));
    else cfg[k] = Math.round((Number(cfg[k]) + d * curStep) * 10) / 10;
    updateDisplay(cfg, DEFAULTS);
    applyToDOM(cfg);
  }
  function saveCfg() { localStorage.setItem(SAVE_KEY, JSON.stringify(cfg)); alert('✅ 저장 완료!'); }
  function resetCfg() {
    if (!confirm('기본값으로 초기화할까요?')) return;
    cfg = Object.assign({}, DEFAULTS);
    localStorage.removeItem(SAVE_KEY);
    rebuild(); updateDisplay(cfg, DEFAULTS);
  }

  // ── 소규모 페이지 빌드 ──
  // 상단: top-wrap (page 기준 절대좌표)
  // 하단: cutline-wrap (커트라인 기준 절대좌표)
  function buildPage(c) {
    var chk = getChk(c.paymentMethod);
    var total = calcTotal(c);
    var svcs = c.services&&c.services.length ? c.services : [{type:'일반방제',price:c.price}];
    var eq = c.equipment;
    var rows = svcs.slice();
    if (eq&&eq.enabled&&eq.count&&eq.pricePerUnit)
      rows.push({type:eq.equipmentName||'설치장비', area:eq.count,
        unitPrice:eq.pricePerUnit, price:eq.count*eq.pricePerUnit, note:''});

    var tyc = ['t_yc1','t_yc2','t_yc3'];
    var byc = ['b_yc1','b_yc2','b_yc3'];

    function ctrRow(s, i, yKeys) {
      return fld(shrink(s.type||s.name||'',8,cfg.fontSize),'cc1',yKeys[i],cfg,FONT)
        + fld(String(s.area||''),'cc2',yKeys[i],cfg,FONT,'text-align:right;width:28mm;')
        + fld(s.unitPrice ? F(s.unitPrice) : '','cc3',yKeys[i],cfg,FONT,'text-align:right;width:28mm;')
        + fld(F(s.price||0),'cc4',yKeys[i],cfg,FONT,'text-align:right;width:28mm;')
        + fld(s.note||'','cc5',yKeys[i],cfg,FONT);
    }

    // 상단 필드 (page top 기준)
    var topHTML =
        fld(shrink(c.code||'',10,cfg.fontSize),'col1','t_y1',cfg,FONT)
      + fld(shrink(c.name||'',8,cfg.fontSize),'col2','t_y1',cfg,FONT)
      + fld(c.phone||'','col3','t_y1',cfg,FONT)
      + fld(c.ceoName||'','col1','t_y2',cfg,FONT)
      + fld(c.businessNumber||'','col2','t_y2',cfg,FONT)
      + fld(c.phone2||'','col3','t_y2',cfg,FONT)
      + fldAddr(c.address||'','addr_x','t_y3',cfg,FONT)
      + rows.slice(0,3).map(function(s,i){return ctrRow(s,i,tyc);}).join('')
      + fldAmt(c.unpaid,'cp1','t_yp',cfg,FONT)
      + fldAmt(total,'cp2','t_yp',cfg,FONT)
      + fldAmt(N(c.unpaid)+total,'cp3','t_yp',cfg,FONT)
      + fld(chk.dw,'cp4','t_yp',cfg,FONT)
      + fld(chk.auto,'cp5','t_yp',cfg,FONT)
      + fld(chk.card,'cp6','t_yp',cfg,FONT);

    // 하단 필드 (커트라인 기준 — 독립 좌표)
    var botHTML =
        fld(shrink(c.code||'',10,cfg.fontSize),'col1','b_y1',cfg,FONT)
      + fld(shrink(c.name||'',8,cfg.fontSize),'col2','b_y1',cfg,FONT)
      + fld(c.phone||'','col3','b_y1',cfg,FONT)
      + fld(c.ceoName||'','col1','b_y2',cfg,FONT)
      + fld(c.businessNumber||'','col2','b_y2',cfg,FONT)
      + fld(c.phone2||'','col3','b_y2',cfg,FONT)
      + fldAddr(c.address||'','addr_x','b_y3',cfg,FONT)
      + rows.slice(0,3).map(function(s,i){return ctrRow(s,i,byc);}).join('')
      + fldAmt(c.unpaid,'cp1','b_yp',cfg,FONT)
      + fldAmt(total,'cp2','b_yp',cfg,FONT)
      + fldAmt(N(c.unpaid)+total,'cp3','b_yp',cfg,FONT)
      + fld(chk.dw,'cp4','b_yp',cfg,FONT)
      + fld(chk.auto,'cp5','b_yp',cfg,FONT)
      + fld(chk.card,'cp6','b_yp',cfg,FONT);

    return '<div class="page">'
      + '<img class="wm" src="'+WM_IMG+'" style="position:absolute;top:'+wmCfg.offsetY+'px;left:0;width:100%;height:100%;object-fit:fill;opacity:'+wmCfg.opacity/100+';pointer-events:none;z-index:0;">'
      // 상단 wrapper (page 기준)
      + '<div class="top-wrap">'+topHTML+'</div>'
      // 커트라인 wrapper (cutline_y 위치부터 시작, 하단은 여기서 0mm)
      + '<div class="cutline-wrap" style="top:'+cfg.cutline_y+'mm;">'
      + '<div class="cl-line" id="cl-line" style="display:none;"><span class="cl-label">&#9986; '+cfg.cutline_y+'mm</span></div>'
      + botHTML+'</div>'
      + '</div>';
  }

  var clVisible = false;
  function toggleCutline() {
    clVisible = !clVisible;
    var btn=document.getElementById('cl-btn');
    var line=document.getElementById('cl-line');
    if(btn){
      btn.style.background=clVisible?'rgba(239,68,68,0.5)':'rgba(239,68,68,0.2)';
      btn.style.color=clVisible?'#fff':'#fca5a5';
      btn.textContent=clVisible?'✂ 커트라인 선 숨기기':'✂ 커트라인 선 보기';
    }
    if(line) line.style.display=clVisible?'block':'none';
  }

  function rebuild() {
    document.getElementById('form-preview').innerHTML = buildPage(customers[0]);
    applyWm(wmCfg, WM_KEY);
    var line=document.getElementById('cl-line');
    if(line) line.style.display=clVisible?'block':'none';
  }

  function doPrint() {
    var fs=document.getElementById('font-style');
    if(fs) fs.textContent='.f{font-size:'+cfg.fontSize+'pt!important;}';
    document.getElementById('form-preview').innerHTML=
      customers.map(function(c){return buildPage(c);}).join('');
    // 인쇄 머리글에서 title 제거
    var origTitle = document.title;
    document.title = ' ';
    requestAnimationFrame(function(){
      requestAnimationFrame(function(){
        window.print();
        document.title = origTitle;
        setTimeout(function(){rebuild();},300);
      });
    });
  }

  setStep(0.5);
  updateDisplay(cfg, DEFAULTS);
  rebuild();
  applyToDOM(cfg);
  // 인쇄 후 팝업 자동 닫힘
  window.onafterprint = function() { window.close(); };
</script>
</body></html>`);
  win.document.close();
}

// ─── 산업체 팝업 ─────────────────────────────────────
function openIndPopup(customers, yearMonth, staffList) {
  const win = window.open('', '_blank', 'width=1100,height=900');
  if (!win) { alert('팝업이 차단되어 있습니다.'); return; }

  const BTN = `padding:2px 8px;background:rgba(255,255,255,0.15);color:white;border:none;border-radius:4px;cursor:pointer;font-size:14px;`;

  win.document.write(`<!DOCTYPE html>
<html lang="ko"><head><meta charset="UTF-8">
<title>산업체 서비스리포트 ${yearMonth}</title>
<style id="font-style"></style>
<style>
  @page { size:A4 portrait; margin:12.2mm 11.2mm 10.2mm 10.7mm; }
  *{box-sizing:border-box;margin:0;padding:0;}
  html,body{background:transparent;}
  .page{width:188.1mm;height:274.6mm;position:relative;overflow:hidden;}
  .page+.page{page-break-before:always;}
  @media print{
    #panel,.no-print{display:none!important;}
    #preview,body{margin:0!important;padding:0!important;}
    .wm{display:none!important;}
  }
  @media screen{
    #panel{position:fixed;left:0;top:0;width:255px;height:100vh;background:#1e3a8a;overflow-y:auto;z-index:99;}
    #preview{margin-left:265px;padding:10px;}
    .wm{position:absolute;top:0;left:0;width:100%;height:100%;object-fit:fill;pointer-events:none;z-index:0;}
  }
</style></head><body>

<div id="panel">
  <div style="padding:10px;">
    <div style="font-weight:bold;font-size:12px;color:white;margin-bottom:6px;">📐 산업체 좌표 조정</div>
    ${buildPanel(IND_CONTROLS)}
    <div style="display:flex;gap:6px;margin-top:10px;">
      <button onclick="saveCfg()" style="flex:1;padding:7px;background:#22c55e;color:white;border:none;border-radius:5px;cursor:pointer;font-size:12px;font-weight:bold;">💾 저장</button>
      <button onclick="resetCfg()" style="padding:7px 10px;background:rgba(255,255,255,0.15);color:white;border:none;border-radius:5px;cursor:pointer;font-size:11px;">↺ 초기화</button>
    </div>
    <button onclick="doPrint()" id="print-btn" style="width:100%;margin-top:6px;padding:8px;background:#1d4ed8;color:white;border:none;border-radius:5px;cursor:pointer;font-size:12px;font-weight:bold;">🖨️ 인쇄 (${customers.length}명 × 2장)</button>
    <div style="font-size:9px;color:#fde68a;margin-top:4px;line-height:1.5;padding:4px 6px;background:rgba(0,0,0,0.2);border-radius:4px;">
      ⚠ 날짜/시간 머리글 제거:<br>
      인쇄창 → 설정 더보기<br>
      → <b>머리글 및 바닥글</b> 체크 해제
    </div>
    ${wmPanelHTML(BTN)}
    <div style="font-size:9px;color:#93c5fd;margin-top:8px;line-height:1.4;">
      💡 ± 0.5mm씩 조정<br>
      📄 출력 장수: ± 1장<br>
      저장하면 다음에도 유지
    </div>
  </div>
</div>

<div id="preview">
  <div class="no-print" style="font-size:11px;color:#666;padding:0 0 8px;">
    ⬅ 패널에서 좌표 조정 후 💾 저장 → 🖨️ 인쇄 &nbsp;|&nbsp; 미리보기: ${customers[0]?.name || ''}
  </div>
  <div id="form-preview"></div>
</div>

<script>
  const SAVE_KEY      = '${SAVE_KEY_IND}';
  const WM_KEY        = '${WM_IND_KEY}';
  const WM_IMG        = '${WM_IND}';
  const FONT          = '${FONT}';
  const DEFAULTS      = ${JSON.stringify(IND_DEFAULTS)};
  const customers     = ${JSON.stringify(customers)};
  const staffListData = ${JSON.stringify(staffList || [])};

  ${POPUP_COMMON_JS}

  let cfg   = Object.assign({}, DEFAULTS);
  let wmCfg = {offsetY:0, opacity:25, visible:true};
  try { cfg   = Object.assign({}, DEFAULTS, JSON.parse(localStorage.getItem(SAVE_KEY)||'{}')); } catch(e){}
  try { wmCfg = Object.assign({}, wmCfg,   JSON.parse(localStorage.getItem(WM_KEY)||'{}')); } catch(e){}

  function getLandline(phone) {
    if (!phone) return '';
    return (phone.split(/[\/,]/).map(function(p){return p.trim();})
      .filter(function(p){return p&&!p.toUpperCase().includes('F)')&&!p.startsWith('010');})
      .join(', '))||(phone.split(/[\/,]/)[0]?.trim()||'');
  }

  function getStaffMobile(name, list) {
    if (!name||!list||!list.length) return '';
    var s=list.find(function(x){return x.name===name;});
    if (!s) return '';
    return ((s.phone||s.mobile||'').split(/[\/,]/).map(function(p){return p.trim();})
      .find(function(p){return p.startsWith('010');})||'');
  }

  function adj(k, d) {
    if (k === 'copies') cfg[k] = Math.max(1, Math.round(cfg[k] + d));
    else cfg[k] = Math.round((Number(cfg[k]) + d) * 10) / 10;
    updateDisplay(cfg, DEFAULTS);
    applyToDOM(cfg);
    // 인쇄 버튼 텍스트 업데이트
    var pb = document.getElementById('print-btn');
    if (pb) pb.textContent = '🖨️ 인쇄 (' + customers.length + '명 × ' + cfg.copies + '장)';
  }

  function saveCfg() { localStorage.setItem(SAVE_KEY, JSON.stringify(cfg)); alert('✅ 저장 완료!'); }
  function resetCfg() {
    if (!confirm('기본값으로 초기화할까요?')) return;
    cfg = Object.assign({}, DEFAULTS);
    localStorage.removeItem(SAVE_KEY);
    rebuild(); updateDisplay(cfg, DEFAULTS);
  }

  // ── 산업체 페이지 1장 빌드 ──
  function buildOnePage(c) {
    var chk = getChk(c.paymentMethod);
    var total = calcTotal(c);
    var landline = getLandline(c.phone);
    var staffMobile = getStaffMobile(c.staffName, staffListData);
    var svcs = c.services&&c.services.length ? c.services : [{type:'일반방제',price:c.price}];
    var eq = c.equipment;
    var rows = svcs.slice();
    if (eq&&eq.enabled&&eq.count&&eq.pricePerUnit)
      rows.push({type:eq.equipmentName||'설치장비', area:eq.count,
        unitPrice:eq.pricePerUnit, price:eq.count*eq.pricePerUnit, note:''});

    var yKeys = ['yc1','yc2','yc3'];
    var ctrRows = rows.slice(0,3).map(function(s,i){
      return fld(shrink(s.type||s.name||'',8,cfg.fontSize),'cc1',yKeys[i],cfg,FONT)
        + fld(String(s.area||''),'cc2',yKeys[i],cfg,FONT,'text-align:right;width:28mm;')
        + fld(s.unitPrice?F(s.unitPrice):'' ,'cc3',yKeys[i],cfg,FONT,'text-align:right;width:28mm;')
        + fld(F(s.price||0),'cc4',yKeys[i],cfg,FONT,'text-align:right;width:28mm;')
        + fld(s.note||'','cc5',yKeys[i],cfg,FONT);
    }).join('');

    return '<div class="page">'
      + '<img class="wm" src="'+WM_IMG+'" style="position:absolute;top:'+wmCfg.offsetY+'px;left:0;width:100%;height:100%;object-fit:fill;opacity:'+wmCfg.opacity/100+';pointer-events:none;z-index:0;">'
      + fld(shrink(c.code||'',10,cfg.fontSize),'col1','y1',cfg,FONT)
      + fld(shrink(c.name||'',8,cfg.fontSize),'col2','y1',cfg,FONT)
      + fld(landline,'col3','y1',cfg,FONT)
      + fld(c.ceoName||'','col1','y2',cfg,FONT)
      + fld(c.businessNumber||'','col2','y2',cfg,FONT)
      + fld(staffMobile,'col3','y2',cfg,FONT)
      + fldAddr(c.address||'','addr_x','y3',cfg,FONT)
      + ctrRows
      + fldAmt(c.unpaid,'cp_u','yp',cfg,FONT)
      + fldAmt(total,'cp_m','yp',cfg,FONT)
      + fldAmt(N(c.unpaid)+total,'cp_t','yp',cfg,FONT)
      + fld(chk.cash,'cp_cash','yp',cfg,FONT)
      + fld(chk.wire,'cp_wire','yp',cfg,FONT)
      + fld(chk.auto,'cp_auto','yp',cfg,FONT)
      + fld(chk.card,'cp_card','yp',cfg,FONT)
      + '</div>';
  }

  // copies 장수만큼 반복
  function buildPages(c) {
    var n = Math.max(1, cfg.copies || 2);
    var html = '';
    for (var i = 0; i < n; i++) html += buildOnePage(c);
    return html;
  }

  function rebuild() {
    document.getElementById('form-preview').innerHTML = buildOnePage(customers[0]);
    applyWm(wmCfg, WM_KEY);
  }

  function doPrint() {
    var fs=document.getElementById('font-style');
    if(fs) fs.textContent='.f{font-size:'+cfg.fontSize+'pt!important;}';
    document.getElementById('form-preview').innerHTML=
      customers.map(function(c){return buildPages(c);}).join('');
    var origTitle = document.title;
    document.title = ' ';
    requestAnimationFrame(function(){
      requestAnimationFrame(function(){
        window.print();
        document.title = origTitle;
        setTimeout(function(){rebuild();},300);
      });
    });
  }

  setStep(0.5);
  updateDisplay(cfg, DEFAULTS);
  rebuild();
  applyToDOM(cfg);
  window.onafterprint = function() { window.close(); };
</script>
</body></html>`);
  win.document.close();
}

// ─── Public API ───────────────────────────────────────
export function printSmallReports(customers, yearMonth) {
  openSmallPopup(customers, yearMonth);
}

export function printIndustrialReports(customers, yearMonth, serviceDates, staffList) {
  openIndPopup(customers, yearMonth, staffList);
}

export function previewReport(customer, yearMonth, serviceDate, bizType, staffList) {
  if (bizType === 'industrial') {
    openIndPopup([customer], yearMonth, staffList);
  } else {
    openSmallPopup([customer], yearMonth);
  }
}
